+            403 => Self::Forbidden(message),
+            404 => Self::NotFound(message),
+            429 => {
+                let retry_after_ms = extract_retry_after(body).unwrap_or(5000);
+                Self::RateLimited { retry_after_ms }
+            }
+            _ => Self::Api {
+                status_code: status,
+                message,
+                request_id,
+            },
+        }
+    }
